const body = $input.first().json.body || $input.first().json;
const taskId = body.taskId || body.task_id || body.task?.id || '';
return [{ json: { taskId, prosseguir: taskId !== '' } }];

const task = $input.first().json;
const cf = task.custom_fields || [];
const cfMap = {};
for (const f of cf) cfMap[f.id] = f;

const getVal = (id) => {
  const f = cfMap[id];
  if (!f) return '';
  if (f.type_config?.options) {
    const opt = f.type_config.options.find(o => o.orderindex === f.value || o.id === f.value);
    return opt?.name || String(f.value || '');
  }
  if (f.type === 'date') return f.value ? new Date(parseInt(f.value)).toLocaleDateString('pt-BR') : '';
  if (f.type === 'currency') {
    const v = f.value ? parseFloat(f.value)/100 : 0;
    return 'R$ ' + v.toLocaleString('pt-BR',{minimumFractionDigits:2,maximumFractionDigits:2});
  }
  return f.value != null ? String(f.value).trim() : '';
};
const getNum = (id) => {
  const f = cfMap[id];
  if (!f || !f.value) return 0;
  if (f.type === 'currency') return parseFloat(f.value)/100;
  return parseFloat(f.value)||0;
};

const UF_NOME = {AC:'Acre',AL:'Alagoas',AM:'Amazonas',AP:'Amapá',BA:'Bahia',CE:'Ceará',DF:'Distrito Federal',
  ES:'Espírito Santo',GO:'Goiás',MA:'Maranhão',MG:'Minas Gerais',MS:'Mato Grosso do Sul',MT:'Mato Grosso',
  PA:'Pará',PB:'Paraíba',PE:'Pernambuco',PI:'Piauí',PR:'Paraná',RJ:'Rio de Janeiro',RN:'Rio Grande do Norte',
  RO:'Rondônia',RR:'Roraima',RS:'Rio Grande do Sul',SC:'Santa Catarina',SE:'Sergipe',SP:'São Paulo',TO:'Tocantins'};
const COMARCA_MAP = {CE:'Fortaleza',PI:'Teresina',MA:'São Luís',BA:'Salvador',PE:'Recife',PB:'João Pessoa',
  RN:'Natal',AL:'Maceió',SE:'Aracaju',PA:'Belém',AM:'Manaus',RJ:'Rio de Janeiro',SP:'São Paulo',
  MG:'Belo Horizonte',PR:'Curitiba',SC:'Florianópolis',RS:'Porto Alegre',GO:'Goiânia',DF:'Brasília',
  MT:'Cuiabá',MS:'Campo Grande',RO:'Porto Velho',AC:'Rio Branco',AP:'Macapá',RR:'Boa Vista',TO:'Palmas',ES:'Vitória'};

const uf = getVal('20fe659f-9eef-4aa4-b170-a7e00cd687e8');
const estadoNome = UF_NOME[uf] || uf;
const orgaoAut = getVal('6b771374-ef1b-42dd-af5a-ffb231e29112');
const orgaoPrefix = orgaoAut.split('/')[0] || 'DETRAN';

let orgaoCab = '';
if (orgaoPrefix === 'DETRAN') orgaoCab = 'DIRETOR/SUPERINTENDENTE DO DEPARTAMENTO ESTADUAL DE TRÂNSITO DO ' + estadoNome.toUpperCase() + ' – DETRAN/' + uf;
else if (orgaoPrefix === 'DNIT') orgaoCab = 'SUPERINTENDENTE DO DEPARTAMENTO NACIONAL DE INFRAESTRUTURA DE TRANSPORTES – DNIT';
else if (orgaoPrefix === 'PRF') orgaoCab = 'SUPERINTENDENTE DA POLÍCIA RODOVIÁRIA FEDERAL – PRF';
else orgaoCab = 'AUTORIDADE COMPETENTE – ' + orgaoAut;

let orgaoExtenso = '';
if (orgaoPrefix === 'DETRAN') orgaoExtenso = 'Departamento Estadual de Trânsito do ' + estadoNome + ' (DETRAN/' + uf + ')';
else if (orgaoPrefix === 'DNIT') orgaoExtenso = 'Departamento Nacional de Infraestrutura de Transportes (DNIT)';
else if (orgaoPrefix === 'PRF') orgaoExtenso = 'Polícia Rodoviária Federal (PRF)';
else orgaoExtenso = orgaoAut;

const MESES = ['janeiro','fevereiro','março','abril','maio','junho','julho','agosto','setembro','outubro','novembro','dezembro'];
const now = new Date();
const brt = new Date(now.getTime() - 3*3600000);
const dataExtenso = brt.getUTCDate() + ' de ' + MESES[brt.getUTCMonth()] + ' de ' + brt.getUTCFullYear();
const dtBRT = brt.toLocaleString('pt-BR',{timeZone:'UTC'});

const valorTotal = getNum('b8647ffd-7a76-4790-90cf-8e6314e5e469');
const valorTotalFmt = 'R$ ' + valorTotal.toLocaleString('pt-BR',{minimumFractionDigits:2});
const parcelas = getNum('1abdab74-70ed-41c4-96af-7a791c8b9e23');
const valorParcela = getNum('f1b84911-ea3d-4e78-a03a-03cc866c6b83');
const valorParcelaFmt = 'R$ ' + valorParcela.toLocaleString('pt-BR',{minimumFractionDigits:2});
const op1 = getVal('4b52ce26-707e-480c-8bb5-471d38a5fc9a');
const op2 = getVal('7bcf3b5b-1403-40e3-a77d-28f08b0c6208');
const dataVenc = getVal('2232c1e7-4087-4245-8405-ca5e4735c594');
const fp = getVal('be4fac1c-4178-4a0c-8315-69747e2af05f');

let opcaoPag = '';
if (op1 && op2) { opcaoPag = op1 + '\n' + op2; }
else if (op1) { opcaoPag = op1; }
else if (fp.includes('PIX')) { opcaoPag = 'Pagamento à vista – valor total de ' + valorTotalFmt + ', via PIX, até ' + dataVenc + '.'; }
else if (fp.includes('Cartão')) { opcaoPag = 'Cartão de Crédito – ' + valorTotalFmt + ' em ' + parcelas + 'x de ' + valorParcelaFmt + ', 1ª parcela até ' + dataVenc + '.'; }
else if (fp.includes('Boleto')) { opcaoPag = 'Boleto Bancário – ' + valorTotalFmt + ' em ' + parcelas + 'x de ' + valorParcelaFmt + ', vencimento em ' + dataVenc + '.'; }
else { opcaoPag = fp + ' – Total: ' + valorTotalFmt; }

const placeholders = {
  '{{NOME_COMPLETO}}': task.name.toUpperCase(),
  '{{NACIONALIDADE}}': getVal('8fc07513-38ca-4ba8-861d-3cc22d52e91f') || 'brasileiro(a)',
  '{{CPF}}': getVal('26b4ecd6-6963-4160-a554-30cd4f36a70c'),
  '{{RG}}': getVal('f36e9cb0-f9d2-4cb8-91ea-e5014a2566c7'),
  '{{UF_ORGAO}}': uf,
  '{{CNH_NUMERO}}': getVal('cbefb914-0e29-4611-b992-b689d0b0fbb1'),
  '{{CNH_CATEGORIA}}': getVal('eda497ef-b8aa-4c1a-a512-3de5b7245aa3'),
  '{{ENDERECO_COMPLETO}}': getVal('7eae45ba-94b4-4cb4-bd1b-927ef11b8107'),
  '{{NUMERO_AIT}}': getVal('e220c08f-03dd-487a-a8a2-6cf25e5bf9d3'),
  '{{ORGAO_DESTINO_CABECALHO}}': orgaoCab,
  '{{ORGAO_SIGLA}}': orgaoAut,
  '{{ORGAO_AUTUADOR_EXTENSO}}': orgaoExtenso,
  '{{ORGAO_ESTADO}}': estadoNome,
  '{{CIDADE_UF}}': 'Fortaleza/CE',
  '{{DATA_CONTRATO_EXTENSO}}': dataExtenso,
  '{{OBJETO_CONTRATO}}': getVal('02b1dd48-1adf-4c70-b277-553ff8681b45'),
  '{{OPCAO_PAGAMENTO}}': opcaoPag,
  '{{COMARCA}}': COMARCA_MAP[uf] || 'Fortaleza',
  '{{VALOR_TOTAL}}': valorTotalFmt,
};

const nomeArquivo = task.name.replace(/[^a-zA-Z0-9 ]/g,'').replace(/\s+/g,'_').toUpperCase();
const dataArq = brt.toISOString().slice(0,10).replace(/-/g,'');

return [{ json: {
  taskId: task.id, taskName: task.name, taskUrl: task.url,
  placeholders, nomeArquivo, dataArq, dtBRT,
  templates: [
    { tipo: 'requerimento', templateId: '1ywVcGwnsRmVlwnJB0Xp3yi2zJLB1uXp-Gxv0un2a7LE' },
    { tipo: 'procuracao',   templateId: '1WOKxYpTpOYCby-az6wXz-DkI55u3Jd3kdoDv7GYZiHA' },
    { tipo: 'contrato',     templateId: '1hQ0FDA6x9BM29Y2KyH3XGcnEbX5Wh_YFf8lbxf2tPxU' },
  ]
} }];

const dados = $('Montar Placeholders').first().json;
const folderId = $('Criar Pasta Cliente').first().json.id;
const tpl = $input.first().json;
return [{ json: { ...tpl, folderId,
  novoNome: dados.nomeArquivo + '_' + tpl.tipo.toUpperCase() + '_' + dados.dataArq,
  taskId: dados.taskId, taskName: dados.taskName, taskUrl: dados.taskUrl,
  nomeArquivo: dados.nomeArquivo, dataArq: dados.dataArq, dtBRT: dados.dtBRT,
  placeholders: dados.placeholders
} }];

const copy = $input.first().json;
const prep = $('Preparar Cópia').first().json;
return [{ json: { ...copy, tipo: prep.tipo, taskId: prep.taskId, taskName: prep.taskName,
  taskUrl: prep.taskUrl, nomeArquivo: prep.nomeArquivo, dataArq: prep.dataArq,
  dtBRT: prep.dtBRT, placeholders: prep.placeholders, folderId: prep.folderId } }];

const dados = $('Montar Placeholders').first().json;
const contratoId = $('Copiar Templates').all().find(i => i.json.tipo === 'contrato')?.json?.id || '';
const reqId = $('Copiar Templates').all().find(i => i.json.tipo === 'requerimento')?.json?.id || '';
const procId = $('Copiar Templates').all().find(i => i.json.tipo === 'procuracao')?.json?.id || '';

const linkBase = 'https://docs.google.com/document/d/';
const contratoLink = contratoId ? linkBase + contratoId + '/edit' : 'não gerado';
const reqLink = reqId ? linkBase + reqId + '/edit' : 'não gerado';
const procLink = procId ? linkBase + procId + '/edit' : 'não gerado';

const comentario = `📄 MF02 — MINUTA GERADA
Data: ${dados.dtBRT} (BRT)
—
📝 Contrato Editável: ${contratoLink}
📝 Requerimento: ${reqLink}
📝 Procuração: ${procLink}
—
Campo "Contrato Editável URL" atualizado no ClickUp.
⏳ Aguardando conferência da equipe → altere o campo "Contrato Revisado Manual" para Validado ou Corrigir Minuta.`;

return [{ json: { taskId: dados.taskId, comentario, contratoLink, contratoId } }];

